      out.write("\r\n");
      out.write("    // -----------------------------------------------------\r\n");
      out.write("    // 0) Inisialisasi Instance Select2 untuk Bank MIV (Menggantikan Tom Select)\r\n");
      out.write("    // -----------------------------------------------------\r\n");
      out.write("    // Menggunakan jQuery ($) karena Select2 membutuhkan jQuery\r\n");
      out.write("    $('#bank_miv').select2({\r\n");
      out.write("        placeholder: \"-- Pilih Bank MIV --\",\r\n");
      out.write("        allowClear: true,\r\n");
      out.write("        width: '100%' // Memastikan lebar penuh mengikuti grid Tailwind\r\n");
      out.write("    }); \r\n");
      out.write("\r\n");
      out.write("    $('#diswil').select2({\r\n");
