      out.write("    // -------------------------\r\n");
      out.write("    // 3) convert bulan nama -> YYYYMM\r\n");
      out.write("    // -------------------------\r\n");
      out.write("    function convertBulanTahunToYYYYMM(input) {\r\n");
      out.write("        if (!input) return '';\r\n");
      out.write("        const bulanMap = {\r\n");
      out.write("            \"Januari\": \"01\", \"Februari\": \"02\", \"Maret\": \"03\",\r\n");
      out.write("            \"April\": \"04\", \"Mei\": \"05\", \"Juni\": \"06\",\r\n");
      out.write("            \"Juli\": \"07\", \"Agustus\": \"08\", \"September\": \"09\",\r\n");
      out.write("            \"Oktober\": \"10\", \"November\": \"11\", \"Desember\": \"12\"\r\n");
      out.write("        };\r\n");
      out.write("        const parts = input.split(\" \");\r\n");
      out.write("        const bulan = bulanMap[parts[0]] || '';\r\n");
      out.write("        const tahun = parts[1] || '';\r\n");
      out.write("        return tahun + bulan;\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    // -------------------------\r\n");
      out.write("    // 4) Load Bank MIV (Diubah penuh ke Gaya Manipulasi DOM Select2)\r\n");
      out.write("    // -------------------------\r\n");
      out.write("    async function loadBankMIV() {\r\n");
      out.write("        console.log(\"🔄 Memuat daftar bank MIV...\");\r\n");
      out.write("        const params = new URLSearchParams();\r\n");
      out.write("        params.append('act', 'getNamaBank');\r\n");
      out.write("        params.append('kdbank', '');\r\n");
      out.write("\r\n");
      out.write("        try {\r\n");
      out.write("            const res = await fetch(getContextPath() + '/mst-global', {\r\n");
      out.write("                method: 'POST',\r\n");
      out.write("                headers: { 'Content-Type': 'application/x-www-form-urlencoded' },\r\n");
      out.write("                body: params.toString()\r\n");
      out.write("            });\r\n");
      out.write("            if (!res.ok) throw new Error(\"HTTP Error \" + res.status);\r\n");
      out.write("            const json = await res.json();\r\n");
      out.write("\r\n");
      out.write("            // Ambil element native select\r\n");
      out.write("            const $bankSelect = $('#bank_miv');\r\n");
      out.write("            \r\n");
      out.write("            // Bersihkan data lama dengan cara standard Select2\r\n");
      out.write("            $bankSelect.empty().trigger(\"change\");\r\n");
      out.write("            \r\n");
      out.write("            // Tambahkan kembali default placeholder option\r\n");
      out.write("            $bankSelect.append(new Option('-- Pilih Bank MIV --', ''));\r\n");
      out.write("\r\n");
      out.write("            if (json.status === 'success' && Array.isArray(json.data)) {\r\n");
      out.write("                // Loop data dan masukkan ke element via Select2 Option constructor\r\n");
      out.write("                json.data.forEach(bank => {\r\n");
      out.write("                    const newOption = new Option(bank.NAMA_BANK, bank.KODE_ERP, false, false);\r\n");
      out.write("                    $bankSelect.append(newOption);\r\n");
      out.write("                });\r\n");
      out.write("                \r\n");
      out.write("                // Beri tahu Select2 untuk me-render ulang UI-nya setelah DOM berubah\r\n");
      out.write("                $bankSelect.trigger('change');\r\n");
      out.write("                console.log(\"✅ Bank MIV berhasil dimuat ke Select2:\", json.data.length, \"data\");\r\n");
      out.write("            } else {\r\n");
      out.write("                $bankSelect.append(new Option('Tidak ada data bank', ''));\r\n");
      out.write("                $bankSelect.trigger('change');\r\n");
      out.write("            }\r\n");
      out.write("        } catch (err) {\r\n");
      out.write("            console.error(\"❌ Error JS:\", err.message);\r\n");
      out.write("        }\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
